mapper.select:
select taskId,nodeId,nodeName,cronExpress,nodeFlowName,id,sourceType,sourceTableName,sourceTableProject,targetType, targetTableName, targetTableProject,createTime, beginRunningTime, finishTime, taskTotalTime, taskAverageTraffic, recordWritingSpeed, readRecords, readFailureRecords, writeRecords, synchronizationStatus from( select distinct mn.task_id as taskId, nodeId,nodeName,cronExpress,nodeFlowName, mn.id , source_type as sourceType,source_table_name as sourceTableName, source_table_project as sourceTableProject,target_type as targetType,target_table_name as targetTableName, target_table_project as targetTableProject,to_char(create_time,'yyyy-mm-dd HH24:mi:ss') as createTime,to_char(begin_running_time,'yyyy-mm-dd HH24:mi:ss') as beginRunningTime, to_char(finish_time,'yyyy-mm-dd HH24:mi:ss') as finishTime,task_total_time as taskTotalTime,TASK_AVERAGE_TRAFFIC as taskAverageTraffic, RECORD_WRITING_SPEED as recordWritingSpeed ,READ_RECORDS as readRecords ,READ_FAILURE_RECORDS as readFailureRecords, (READ_RECORDS - READ_FAILURE_RECORDS) as writeRecords, case when mn.status is null then 1 else mn.status end as synchronizationStatus from (select n.nodeId,n.nodeFlowName,n.nodeName,n.cronExpress,n.node_type,m3.id,m3.task_id,m3.STATUS, m3.FINISH_TIME,m3.begin_running_time,m3.create_time from (select distinct NODE_ID as nodeId, ODPSPROJECT_NAME as nodeFlowName, NODE_NAME as nodeName, CRON_EXPRESS as cronExpress, node_type from m_node_three where prg_type = 23
and upper(NODE_NAME) like upper('%${nodeNameInput}%')
) n left join (select id,task_id,node_id,STATUS,FINISH_TIME,begin_running_time,create_time from (select m1.id, m1.task_id,m1.node_id,m1.STATUS, m1.FINISH_TIME,m1.begin_running_time,m1.create_time, ROW_NUMBER() over(partition by task_id order by INSERT_TIME desc) as num from m_flow_three m1 where BEGIN_RUNNING_TIME >= TO_DATE(#{taskOpenDate}, 'yyyy-mm-dd HH24:mi:ss') and FINISH_TIME <= TO_DATE(#{taskEndDate}, 'yyyy-mm-dd HH24:mi:ss') and prg_type =23) m2 where m2.num = 1) m3 on n.nodeid = m3.node_id ) mn left join (select TASK_ID,ID,SOURCE_TYPE,SOURCE_TABLE_NAME,SOURCE_TABLE_PROJECT,TARGET_TYPE, TARGET_TABLE_NAME,TARGET_TABLE_PROJECT,TASK_TOTAL_TIME,TASK_AVERAGE_TRAFFIC,RECORD_WRITING_SPEED, READ_RECORDS,READ_FAILURE_RECORDS,TASK_START_TIME,TASK_END_TIME,SYNCHRONIZATION_STATUS,MESSGAE_INSERT_TIME from (select t1.TASK_ID,t1.ID,t1.SOURCE_TYPE,t1.SOURCE_TABLE_NAME,t1.SOURCE_TABLE_PROJECT,t1.TARGET_TYPE, t1.TARGET_TABLE_NAME,t1.TARGET_TABLE_PROJECT,t1.TASK_TOTAL_TIME,t1.TASK_AVERAGE_TRAFFIC,t1.RECORD_WRITING_SPEED, t1.READ_RECORDS,t1.READ_FAILURE_RECORDS,t1.TASK_START_TIME,t1.TASK_END_TIME,t1.SYNCHRONIZATION_STATUS,t1.MESSGAE_INSERT_TIME, ROW_NUMBER() over(partition by TASK_ID order by MESSGAE_INSERT_TIME desc) as num from task_run_analyze t1 where task_id is not null ) where num = 1 union all select TASK_ID,ID,SOURCE_TYPE,SOURCE_TABLE_NAME,SOURCE_TABLE_PROJECT,TARGET_TYPE, TARGET_TABLE_NAME,TARGET_TABLE_PROJECT,TASK_TOTAL_TIME,TASK_AVERAGE_TRAFFIC,RECORD_WRITING_SPEED, READ_RECORDS,READ_FAILURE_RECORDS,TASK_START_TIME,TASK_END_TIME,SYNCHRONIZATION_STATUS,MESSGAE_INSERT_TIME from (select t1.TASK_ID,t1.ID,t1.SOURCE_TYPE,t1.SOURCE_TABLE_NAME,t1.SOURCE_TABLE_PROJECT,t1.TARGET_TYPE, t1.TARGET_TABLE_NAME,t1.TARGET_TABLE_PROJECT,t1.TASK_TOTAL_TIME,t1.TASK_AVERAGE_TRAFFIC,t1.RECORD_WRITING_SPEED, t1.READ_RECORDS,t1.READ_FAILURE_RECORDS,t1.TASK_START_TIME,t1.TASK_END_TIME,t1.SYNCHRONIZATION_STATUS,t1.MESSGAE_INSERT_TIME, ROW_NUMBER() over(partition by id order by MESSGAE_INSERT_TIME desc) as num from task_run_analyze t1 where id is not null ) where num = 1 ) t2 on mn.task_id ||mn.id = t2.task_id||t2.id where 1 = 1
)

select message from(
  select message ,ROW_NUMBER() over(partition by ID||TASK_ID  order by INSERT_TIME desc) as num from(
  select message,id,TASK_ID,INSERT_TIME from task_run_log


          task_id =#{taskId}


          and id = #{id}


  )) where num = 1
